mapper.select:
SELECT
    id, warehouse_id, zone_id, code, loc_type, status, deleted,
    created_at, updated_at, created_by, updated_by
FROM location
WHERE deleted = 0

    AND code LIKE CONCAT('%', #{keyword}, '%')


    AND warehouse_id = #{warehouseId}


    AND zone_id = #{zoneId}


    AND status = #{status}

ORDER BY warehouse_id ASC, code ASC, id ASC
